VALUES
  ('social-worker-moex-03186', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '直接使用「臺灣世界價值觀調查」資料庫，研究國人子女教養及婚姻態度等價值變化，在方法上它屬於：', '["問卷調查", "敘事研究", "歷史分析", "次級資料分析"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03187', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '相較其他研究方法，下列有關內容分析的敘述，何者錯誤？', '["費錢、耗時是它的缺點", "不介入、容易更正錯誤是它的優點", "它可以是量化的，也可以是質化的技術", "它可以應用在對社會工作個案紀錄的分析上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03188', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '實驗設計（experimental design）與準實驗設計（quasi-experimental design）二者最主要差異是：', '["控制組人數", "對照組人數", "取樣單位隨機化", "實驗組人數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03189', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何種情形，採用中位數（median）要比使用平均數（mean）適當？', '["平均數值很大時", "需要有高效度時", "平均數與眾數相差太大時", "極端分數對於平均數影響太大時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03190', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當進行統計顯著性檢定時，發現p＜0.05顯著水準，研究者拒絕虛無假設時，下列敘述何者正確？', '["以這個樣本結果來推論母群體時，只有小於5%的可能性是由抽樣誤差所造成的", "有高於或等於95%的機會，樣本結果純粹的由機會所造成，而它可以充分反映母群體特質", "我們有高於或等於95%的信心，認為虛無假設是正確，而虛無假設是研究者內心所支持的", "當p＜0.05時會出現一顆星星（*），它直接證明了變項和變項之間的確有關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03191', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想經由前、後測成績的方式，瞭解一個由10人所組成的社工研究法讀書團體運作成效。他使用 成對樣本t檢定，95%信賴區間設定，得到數據如下：前測平均數80.20（標準差8.55）、後測平均數84.20 （標準差4.52），樣本相關係數0.822，p＝0.004，t值＝2.31，p＝0.046。下列有關敘述，何者正確？', '["這10名讀書團體成員前後測成績，沒有顯著不同", "這10名讀書團體成員前後測成績，有顯著不同", "前測成績要比後測成績好，因為標準差比較大", "前後測的成績，因標準差不同，無從比較起"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03192', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關質化資料分析編碼（coding）的敘述，何者錯誤？', '["編碼是機械式的將資料縮減、並加以分析歸類的工作", "開放式編碼（open coding）是研究者根據最初的研究問題或文獻概念，讓大量資料濃縮成幾個類別的方 法，它的抽象程度最高", "主軸式編碼（axial coding）是資料的第二層過濾，目的在把開放式編碼所得結果加以組織，使產生新概 念的方法", "選擇式編碼（selective coding）是研究者對資料的最後一項處理，目的在聚攏已發展的範疇，並藉此形 成核心概念"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03193', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '從事社會工作研究必須留意那些研究倫理：①自願參與及告知同意、尊重當事人或其家長（監護人）的', '["保護參與者免受身心傷害", "確保研究資料的隱密性、避免蒐集非必要性的意見或個人資料", "避免隱瞞與欺騙受試者  ⑤用福利服務補償受試者的損失", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03194', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關集體施測法的陳述何者為真？①省時省錢  ②回收率高  ③可以確定受試者為本人  ④在答案 填寫的細微程度上，優於訪問調查法  ⑤需有強有力的行政系統及場地的配合', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03195', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '又稱抽回和反轉（withdrawal/reversal）設計，對外在事件有較好的控制，但須注意倫理問題以及不可逆 轉性問題的是那一種單案設計？', '["AB設計", "ABAB設計", "多重基線設計（multiple-baseline）", "多種組合設計（multiple-component）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03196', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '通常在次數分配表中會有一項“未答＂類別，是用來表示受訪者遺漏而沒有回答者，或無法編碼者。在 資料分析中，這類資料是屬於無效值，當一個變項有超過多少比率的無效值出現時，就要慎重考慮剩下 資料的計量效度與信度了？', '["10%", "20%", "30%", "50%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03197', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關同樣本多次研究（panel study）的陳述何者為真？①比較能看到改變的全貌  ②因成本較低較容', '["有樣本損耗率太高的問題", "早期從事觀察的過程可能會影響後來的行為", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03198', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為瞭解大學生對兩性平權態度是否有所改變，李教授研究在1960 年畢業之大學生對兩性平權態度的變化。 此後每隔10年（也就是1970，1980，1990，2000，2010）李教授就從該年之畢業生抽出新的樣本進行調 查。請問李教授乃從事何種研究？', '["橫斷性研究（cross-sectional study）", "世代研究（cohort study）", "因果研究（causal study）", "同樣本多次研究（panel study）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03199', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者不是分層抽樣（stratified sampling）的特徵？', '["母體被分成內部異質的次群體", "企圖使次群體內同質，而次群體間異質", "抽樣時從次群體內隨機選取元素", "比簡單隨機抽樣更具代表性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03200', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關質化研究和量化研究的差異，何者為真？①量化研究根據的理論是邏輯實證論；質化研究根據', '["量化研究所運用的邏輯是歸納法；質化研究所運用的邏輯是演繹法", "量化研究假 定實體（reality）是靜態的；質化研究假定實體（reality）是動態的", "量化研究的結果是特殊的，可概 推的；質化研究的結果是完整的，不可概推的", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03201', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在田野研究（field research）的訪談中，訪談者：', '["可以對訪談對象透露自己的背景或興趣以建立信任關係", "必須對訪談對象讀出問卷上的每個問題", "不可使用探問（probe）或追問（follow-up questions）", "不可對任何一位訪談對象調整問題形式或問法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03202', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '如何避免測量誤差？①設計問卷時，儘量避免有偏見的字眼  ②儘量用受訪者能了解的字句  ③確認訪', '["確定受訪者了解他是被研究的對象  ⑤採三角測量法（triangulation）", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03203', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一項虛假的關係（spurious relationship）指的是：', '["兩個變項之間有正相關", "當考量其他變項的影響時，原來兩變項的關係就消失", "自變項發生的時間比應變項晚", "使用歸納邏輯而非演繹邏輯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03204', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於信度與效度，以下那一個敘述是正確的？', '["一個有信度的測量是有效的", "效度較信度更容易達成", "一個有效的測量是可信的", "若我們知道測量是可信的，就不太需要注意其效度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03205', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '倘若實驗的前測與後測間隔的時間很短，那麼：', '["歷史（history）效應更可能發生", "統計迴歸（statistical regression）效應更可能發生", "測量（testing）效應更不可能發生", "成熟（maturation）效應更不可能發生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03206', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者欲建立一項因果關係時，不需要以下那一項條件？', '["統計關聯（statistical association）", "時間先後順序", "中介變項（mediating variable）", "替代性解釋的排除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03207', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社工組織的人力組合越來越多元化，如果聘用原本需要被照顧的人口群進入服務人力之中，這樣的作法 主要稱為：', '["肯定行動（affirmative action）", "重視差異（valuing difference）", "管理多元（managing diversity）", "超越族群（beyond race）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03208', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '為了組織目的所設立的部門稱為「技術核心」，在其中工作的是「直線工作人員」，服務於第一線。在 住宿型身心障礙機構中的直線工作者是：', '["秘書", "督導", "老師", "教保人員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03209', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以下都是人群服務組織在規劃方案過程中需要進行的步驟，那一個步驟是最先要做的？', '["建立目標與標的", "準備預算", "需求評估", "監督方案輸送"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03210', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對社工員進行訓練是很普遍的，要衡量訓練的結果，依照「評估訓練方案的技術」中的四種層次，著重 受訓者能否將訓練的學習成果移轉到工作上，這是下列那一層次的效果？', '["反應層次", "學習層次", "行為層次", "結果層次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
